    "id": "commando-music-box",
    "label": "Commando Music Box",
    "detail": "Title-screen plus keypad music-box demo kept in legacy-compat for its state-machine style.",
    "projectName": "commando-music-box",
    "sourceLang": "amy",
    "selectedLibs": [],
